mapper.select:
SELECT t1.project_name, t1.project_id, t1.create_time, t1.create_by, t1.update_by, t1.update_time, t2.name as projectHeadName
FROM sys_project t1 left join sys_worker_user t2 on t2.id = t1.project_head_id
and t1.project_id = #{sysProjectVo.projectId}
and t1.create_time BETWEEN #{sysProjectVo.createTime} and #{sysProjectVo.endTime}
order by t1.create_time desc
